{"cmd":"cat > /app/mystery.c <<'EOF'
#include <math.h>
#include <stdio.h>
#include <stdlib.h>

typedef struct {
  float x, y, z;
} V;

typedef struct {
  V o, d;
} Ray;

typedef struct {
  float t;
  V p, n;
  int hit;
} Hit;

static V add(V a, V b) { return (V){a.x + b.x, a.y + b.y, a.z + b.z}; }
static V sub(V a, V b) { return (V){a.x - b.x, a.y - b.y, a.z - b.z}; }
static V mul(V a, float s) { return (V){a.x * s, a.y * s, a.z * s}; }
static float dot(V a, V b) { return a.x * b.x + a.y * b.y + a.z * b.z; }
static V norm(V v) {
  float l = sqrtf(dot(v, v));
  return (V){v.x / l, v.y / l, v.z / l};
}

static Hit sphere_intersect(Ray r, V c, float radius) {
  V oc = sub(r.o, c);
  float a = dot(r.d, r.d);
  float b = 2.0f * dot(oc, r.d);
  float d = b * b - 4.0f * a * (dot(oc, oc) - radius * radius);
  if (d < 0.0f) return (Hit){0};
  float s = sqrtf(d);
  float t = (-b - s) / (2.0f * a);
  if (t < 0.001f) {
    t = (-b + s) / (2.0f * a);
    if (t < 0.001f) return (Hit){0};
  }
  V p = add(r.o, mul(r.d, t));
  V n = norm(sub(p, c));
  return (Hit){t, p, n, 1};
}

static Hit plane_intersect(Ray r, float y) {
  if (fabsf(r.d.y) < 0.0001f) return (Hit){0};
  float t = y / r.d.y;
  if (t < 0.001f) return (Hit){0};
  V p = add(r.o, mul(r.d, t));
  return (Hit){t, p, (V){0.0f, 1.0f, 0.0f}, 1};
}

static V sky_color(Ray r) {
  float t = 0.5f * (r.d.y + 1.0f);
  return (V){(1.0f - t) + 0.5f * t, (1.0f - t) + 0.7f * t, 1.0f};
}

static int is_in_shadow(V p, V n, V light, V sphere_center, float sphere_radius) {
  Ray s = {add(p, mul(n, 0.001f)), light};
  return sphere_intersect(s, sphere_center, sphere_radius).hit;
}

static V trace(Ray r, V light, V sphere_center, float sphere_radius) {
  Hit sh = sphere_intersect(r, sphere_center, sphere_radius);
  Hit ph = plane_intersect(r, 0.9f);

  if (sh.hit && (!ph.hit || sh.t < ph.t)) {
    float d = 0.2f;
    if (!is_in_shadow(sh.p, sh.n, light, sphere_center, sphere_radius))
      d = 0.2f + 0.8f * fmaxf(0.0f, dot(sh.n, light));
    return (V){d, d * 0.2f, d * 0.2f};
  }

  if (ph.hit) {
    float d = 0.2f;
    if (!is_in_shadow(ph.p, ph.n, light, sphere_center, sphere_radius))
      d = 0.2f + 0.8f * fmaxf(0.0f, dot(ph.n, light));
    int c = ((int)floorf(ph.p.x) + (int)floorf(ph.p.z)) & 1;
    float g = (c ? 0.7f : 0.4f) * d;
    return (V){g, g, g};
  }

  return sky_color(r);
}

static void write_image(const char *path, V *img, int w, int h) {
  FILE *f = fopen(path, "w");
  if (!f) {
    fprintf(stderr, "Error: Could not open file %s for writing\n", path);
    return;
  }
  fprintf(f, "P3\n%d %d\n255\n", w, h);
  for (int y = 0; y < h; y++) {
    for (int x = 0; x < w; x++) {
      V p = img[y * w + x];
      int r = (int)(fminf(fmaxf(p.x, 0.0f), 1.0f) * 255.99f);
      int g = (int)(fminf(fmaxf(p.y, 0.0f), 1.0f) * 255.99f);
      int b = (int)(fminf(fmaxf(p.z, 0.0f), 1.0f) * 255.99f);
      fprintf(f, "%d %d %d\n", r, g, b);
    }
  }
  fclose(f);
  fprintf(stderr, "Wrote image to %s\n", path);
}

int main(void) {
  const int w = 800, h = 600;
  fprintf(stderr, "Creating high-resolution image: %dx%d\n", w, h);
  fwrite("This will be downsampled with ffmpeg after rendering\n", 1, 53, stderr);
  fwrite("Rendering high-resolution image...\n", 1, 35, stderr);

  V *img = (V *)malloc((size_t)w * (size_t)h * sizeof(V));
  if (!img) return 1;

  V light = norm((V){1.0f, 1.0f, -1.0f});
  V sphere_center = {0.0f, -0.5f, -5.0f};

  for (int y = 0; y < h; y++) {
    fprintf(stderr, "\rProgress: %.1f%%", (100.0f * (float)y) / (float)h);
    for (int x = 0; x < w; x++) {
      float fx = ((float)x / 799.0f) * 2.666666746f - 1.333333373f;
      float fy = 1.0f - 2.0f * ((float)y / 599.0f);
      Ray r = {{0.0f, 0.0f, 0.0f}, norm((V){fx, fy, -1.0f})};
      img[y * w + x] = trace(r, light, sphere_center, 1.0f);
    }
  }

  fwrite("\nRendering complete\n", 1, 20, stderr);
  write_image("image.ppm", img, w, h);
  free(img);
  fwrite("Done.\n", 1, 6, stderr);
  return 0;
}
EOF"}

